  "arborg.C.list.21.occupation": "Nurse",
  "arborg.C.list.22.occupation": "Managing Director",
  "arborg.C.list.3.bio": "Þorsteinn Haukur Harðarson is a consultant and is in 3rd place on the Viðreisn list in Árborg in the 2026 municipal elections, where the party is standing in local council elections for the first time.",
  "arborg.C.list.3.occupation": "Consultant",
  "arborg.C.list.4.bio": "Birgir Marteinsson is a lawyer and is in 4th place on the Viðreisn list in Árborg in the 2026 municipal elections. He brings legal expertise to the candidate list and supports Viðreisn’s constructive goals in the municipality.",
  "arborg.C.list.4.occupation": "Lawyer",
  "arborg.C.list.5.bio": "Ingunn Guðmundsdóttir is a business graduate and is in 5th place on the Viðreisn list in Árborg in the 2026 municipal elections. She brings expertise in business and financial matters for the benefit of the municipality.",
  "arborg.C.list.5.occupation": "Business graduate",
