  "gardabaer.B.list.9.occupation": "Business Owner",
  "gardabaer.B.tagline": "Hlynur Bæringsson leads Framsókn in Garðabær",
  "gardabaer.C.agenda.0.text": "Increase social housing in Garðabær — 5% of all new homes should be social housing.",
