  "hafnarfjordur.A.agenda.1.text": "Strong school services and support for children and young people.",
  "hafnarfjordur.A.agenda.1.title": "Education",
  "hafnarfjordur.A.agenda.2.text": "Better public transport and planned development of the town.",
