  "hafnarfjordur.A.list.19.occupation": "Secretary",
  "hafnarfjordur.A.list.2.bio": "Svenný Kristins is a composer and assistant music teacher in Hafnarfjörður. He is on the Left’s candidate list in Hafnarfjörður for the 2026 municipal elections.",
  "hafnarfjordur.A.list.2.occupation": "Occupational therapy assistant, songwriter",
  "hafnarfjordur.A.list.20.occupation": "Sound designer",
  "hafnarfjordur.A.list.21.occupation": "University student",
  "hafnarfjordur.A.list.22.occupation": "Musician",
  "hafnarfjordur.A.list.3.bio": "Davíð Arnar Stefánsson is a geographer and mountain guide who works at the Soil Conservation Service of Iceland in sustainability and climate. He is also a trained horticulturist and carpenter, was born and raised in Hafnarfjörður, and has for many years taken part in public debate on the town’s development.",
  "hafnarfjordur.A.list.3.occupation": "Geographer, mountain guide",
  "hafnarfjordur.A.list.4.bio": "Guðrún Lína Thoroddsen is a filmmaker. She is on the Left’s candidate list in Hafnarfjörður for the 2026 municipal elections.",
  "hafnarfjordur.A.list.4.occupation": "Filmmaker",
  "hafnarfjordur.A.list.5.bio": "Margrét Pétursdóttir is a guide. She is on the Left’s candidate list in Hafnarfjörður for the 2026 municipal elections.",
  "hafnarfjordur.A.list.5.occupation": "Guide",
  "hafnarfjordur.A.list.6.occupation": "Upper secondary school teacher",
  "hafnarfjordur.A.list.7.occupation": "Chair of the National Association of Police Officers",
  "hafnarfjordur.A.list.8.occupation": "Anthropologist and poet",
  "hafnarfjordur.A.list.9.occupation": "Occupational therapist, master’s degree in health sciences",
  "hafnarfjordur.A.tagline": "Ester Bíbí leads the Left in Hafnarfjörður",
  "hafnarfjordur.B.agenda.0.text": "Public health and a healthy lifestyle as a priority.",
  "hafnarfjordur.B.agenda.0.title": "Public health",
  "hafnarfjordur.B.agenda.1.text": "Strong welfare services and support for all residents.",
  "hafnarfjordur.B.agenda.1.title": "Welfare",
  "hafnarfjordur.B.agenda.2.text": "Quality services for children, families and the elderly in the town.",
  "hafnarfjordur.B.agenda.2.title": "Community services",
  "hafnarfjordur.B.agenda.3.text": "\"The future is decided in the centre\" — sensible development of Hafnarfjörður.",
  "hafnarfjordur.B.agenda.3.title": "Vision for the future",
  "hafnarfjordur.B.list.1.bio": "Valdimar Víðisson was born on 10 September 1978 in Ísafjörður and grew up in Bolungarvík. He is a qualified compulsory school teacher with postgraduate studies in management, and worked as headteacher at Grenivíkurskóli from 2004 and later as headteacher of Öldutúnsskóli in Hafnarfjörður from 2008. He was a deputy municipal councillor for Framsókn from 2018 to 2022 and became Mayor of Hafnarfjörður on 1 January 2025.",
  "hafnarfjordur.B.list.1.interests.0": "Education and school services",
  "hafnarfjordur.B.list.1.interests.1": "Development and housing",
  "hafnarfjordur.B.list.1.interests.2": "Transport",
  "hafnarfjordur.B.list.1.interests.3": "Welfare services",
