  "hafnarfjordur.M.list.11.occupation": "Consultant at Klettabær",
  "hafnarfjordur.M.list.12.occupation": "Master painter",
  "hafnarfjordur.M.list.13.occupation": "Managing Director",
  "hafnarfjordur.M.list.14.occupation": "Managing Director and visual artist",
  "hafnarfjordur.M.list.15.occupation": "Estate agent",
  "hafnarfjordur.M.list.16.occupation": "Business graduate",
  "hafnarfjordur.M.list.17.occupation": "Teacher",
  "hafnarfjordur.M.list.18.occupation": "Marine engineer",
  "hafnarfjordur.M.list.19.occupation": "Business owner",
  "hafnarfjordur.M.list.2.bio": "Signý Jóna Tryggvadóttir is a human resources specialist. She is second on the Centre Party’s candidate list in Hafnarfjörður for the 2026 municipal elections.",
  "hafnarfjordur.M.list.2.occupation": "Human resources specialist",
  "hafnarfjordur.M.list.20.occupation": "Sales Manager",
  "hafnarfjordur.M.list.21.occupation": "First mate",
  "hafnarfjordur.M.list.22.occupation": "Driver",
  "hafnarfjordur.M.list.3.bio": "Böðvar Ingi Guðbjartsson is a teacher and master plumber and chairman of the Association of Master Plumbers. He is third on the Centre Party’s candidate list in Hafnarfjörður.",
