  "hafnarfjordur.M.list.9.occupation": "Student",
  "hafnarfjordur.M.tagline": "Einar Geir leads the Centre Party in Hafnarfjörður",
  "hafnarfjordur.S.agenda.0.text": "Advocate for improved public transport and Borgarlína connecting Hafnarfjörður to the Capital Region.",
  "hafnarfjordur.S.agenda.0.title": "Transport",
  "hafnarfjordur.S.agenda.1.text": "Ensure strong welfare services in schools — educational counsellors, psychologists and developmental support for those who need it.",
  "hafnarfjordur.S.agenda.1.title": "Children’s welfare and support in schools",
  "hafnarfjordur.S.agenda.2.text": "Build more quality homes and support healthy and active lives for older residents of Hafnarfjörður.",
