  "kjosarhreppur.KJA.agenda.0.text": "Protecting Kjós and promoting sustainable development in one of the country’s most beautiful areas.",
  "kjosarhreppur.KJA.agenda.0.title": "Nature conservation",
  "kjosarhreppur.KJA.agenda.1.text": "Improve living conditions and infrastructure to strengthen settlement in the municipality.",
  "kjosarhreppur.KJA.agenda.1.title": "Housing",
  "kjosarhreppur.KJA.agenda.2.text": "Strengthen community ties and residents’ participation in governance.",
  "kjosarhreppur.KJA.agenda.2.title": "Community",
  "kjosarhreppur.KJA.list.1.bio": "Sigurður Gunnar Sigurðsson is in 1st place on the KJA candidate list in Kjósarhreppur for the 2026 municipal elections.",
  "kjosarhreppur.KJA.list.1.occupation": "Municipal manager and farmer",
