  "mosfellsbaer.L.list.7.occupation": "Service Representative",
  "mosfellsbaer.L.list.8.occupation": "Teacher and basketball coach",
  "mosfellsbaer.L.list.9.occupation": "Student and handball team captain",
  "mosfellsbaer.L.tagline": "Árni Jónsson leads the Friends of Mosfellsbær — planning on residents’ terms, real transport solutions",
  "mosfellsbaer.M.agenda.0.text": "Preventive support for children with complex needs; coordinated services without unnecessary bureaucracy.",
  "mosfellsbaer.M.agenda.0.title": "Welfare",
  "mosfellsbaer.M.agenda.1.text": "The density in the upper part of Blikastaðir will be reassessed; schools and infrastructure must keep pace with development — not come afterwards.",
  "mosfellsbaer.M.agenda.1.title": "Planning — Blikastaðaland",
  "mosfellsbaer.M.agenda.2.text": "Vesturlandsvegur — cooperation with the Icelandic Road and Coastal Administration; Sundabraut accelerated as a key project.",
  "mosfellsbaer.M.agenda.2.title": "Transport",
  "mosfellsbaer.M.agenda.3.text": "No unnecessary waiting lines — measurable targets set and published publicly; transparency and open access to data.",
  "mosfellsbaer.M.agenda.3.title": "Administration",
  "mosfellsbaer.M.agenda.4.text": "Diverse operating models, including independent providers and childminders; parental choice at the forefront.",
  "mosfellsbaer.M.agenda.4.title": "Preschool matters",
  "mosfellsbaer.M.agenda.5.text": "A new school alongside the Blikastaðir development — a promise we will keep.",
  "mosfellsbaer.M.agenda.5.title": "Primary education",
  "mosfellsbaer.M.list.1.bio": "Sveinn Óskar Sigurðsson was born on 27 July 1968 in Selfoss. He is an economist and philosopher with a BA from the University of Iceland, an MBA and an MSc in Finance from the same university, and spent time at Peking University in 1996–1997 as Morgunblaðið’s correspondent in China. He is heiðurúlfhildur and runs a small consultancy and property valuation company. He has been a municipal councillor for the Centre Party in Mosfellsbær since 2018 and leads the M-list in the 2026 local elections.",
  "mosfellsbaer.M.list.1.interests.0": "Children and families with children first",
  "mosfellsbaer.M.list.1.interests.1": "Welfare and services for those in need",
  "mosfellsbaer.M.list.1.interests.2": "Planning and transport issues (Sundabraut)",
  "mosfellsbaer.M.list.1.interests.3": "Responsible financial management",
  "mosfellsbaer.M.list.1.interests.4": "Environmental protection",
  "mosfellsbaer.M.list.1.occupation": "Business economist and economist",
  "mosfellsbaer.M.list.10.occupation": "Candidate",
