  "mosfellsbaer.M.list.19.occupation": "Candidate",
  "mosfellsbaer.M.list.2.bio": "Ingibjörg Einarsdóttir is a trained dental technician and an associate professor at the University of Iceland. She is second on the Centre Party’s list in Mosfellsbær in the 2026 local elections.",
  "mosfellsbaer.M.list.2.occupation": "Dental technician and associate professor at HÍ",
  "mosfellsbaer.M.list.20.occupation": "Candidate",
  "mosfellsbaer.M.list.21.occupation": "Candidate",
  "mosfellsbaer.M.list.22.occupation": "Candidate",
  "mosfellsbaer.M.list.3.bio": "Hjalti Árnason, known as Hjalti Úrsus, is a former strongman and fitness advocate. He ran Eldingamar, a fitness and strength sports centre by Varmá in Mosfellsbær, from 2007 to 2023.",
  "mosfellsbaer.M.list.3.occupation": "Candidate",
  "mosfellsbaer.M.list.4.bio": "Sóley Sævarsdóttir Meyer is a lawyer and singer. She is a co-founder of Þorpið – Tengslasetrið and is in fourth place on the Centre Party’s list in Mosfellsbær.",
  "mosfellsbaer.M.list.4.occupation": "Candidate",
  "mosfellsbaer.M.list.5.bio": "Kristján Davíð Sigurjónsson is in 5th place on the Centre Party’s candidate list in Mosfellsbær in the 2026 municipal elections.",
  "mosfellsbaer.M.list.5.occupation": "Candidate",
  "mosfellsbaer.M.list.6.occupation": "Candidate",
  "mosfellsbaer.M.list.7.occupation": "Candidate",
  "mosfellsbaer.M.list.8.occupation": "Candidate",
  "mosfellsbaer.M.list.9.occupation": "Candidate",
  "mosfellsbaer.M.tagline": "Sveinn Óskar, lead candidate of the Centre Party in Mosfellsbær — For a vibrant town",
  "mosfellsbaer.S.agenda.0.text": "Increase in financial assistance; social rental housing; free social home care services.",
  "mosfellsbaer.S.agenda.0.title": "Welfare",
  "mosfellsbaer.S.agenda.1.text": "Free preschool; preschool places from 12 months of age; Fab Lab for innovation.",
  "mosfellsbaer.S.agenda.1.title": "Education",
  "mosfellsbaer.S.agenda.2.text": "A new town centre plan; sustainable neighbourhoods with good transport links; climate targets.",
  "mosfellsbaer.S.agenda.2.title": "Planning and environment",
  "mosfellsbaer.S.agenda.3.text": "Strengthen the council of older people; increased public consultation; develop the youth council with a stronger advisory role.",
  "mosfellsbaer.S.agenda.3.title": "Democracy",
  "mosfellsbaer.S.agenda.4.text": "Turn Hlégarður into a cultural centre; find new premises for the Music School.",
  "mosfellsbaer.S.agenda.4.title": "Culture",
  "mosfellsbaer.S.agenda.5.text": "Increased leisure grant (ISK 75,000) for children from the age of 4; support for senior citizens.",
  "mosfellsbaer.S.agenda.5.title": "Sports and leisure",
  "mosfellsbaer.S.agenda.6.text": "Quality education and strong school support services.",
  "mosfellsbaer.S.agenda.6.title": "Education",
  "mosfellsbaer.S.list.1.bio": "Ólafur Ingi Óskarsson is a network engineer and chair of the welfare committee of Mosfellsbær. He has been involved in local politics since 2018 and leads the Social Democratic Alliance’s S-list in the 2026 municipal elections. Among other things, he has advocated for immigrants’ rights and for the acceptance of refugees in Mosfellsbær.",
  "mosfellsbaer.S.list.1.interests.0": "Welfare services and social justice",
  "mosfellsbaer.S.list.1.interests.1": "Preschool system and education",
