  "mosfellsbaer.S.list.1.interests.4": "Nature conservation in Blikastaðaland",
  "mosfellsbaer.S.list.1.occupation": "Network engineer and chair of the welfare committee",
  "mosfellsbaer.S.list.10.occupation": "Candidate",
  "mosfellsbaer.S.list.11.occupation": "Candidate",
