  "reykjanesbaer.M.list.22.occupation": "Honorary member of the Centre Party",
  "reykjanesbaer.M.list.3.bio": "Sigrún Þorsteinsdóttir is a service representative and social care worker. She is third on the Centre Party's candidate list in Reykjanesbær in 2026.",
  "reykjanesbaer.M.list.3.occupation": "Service representative and social care worker",
  "reykjanesbaer.M.list.4.bio": "Bjarni Gunnólfsson is a trained chef. He is fourth on the Centre Party's candidate list in Reykjanesbær in 2026.",
  "reykjanesbaer.M.list.4.occupation": "Chef",
  "reykjanesbaer.M.list.5.bio": "Matthildur Júlía Matthíasdóttir is a care worker and is fifth on the Centre Party's candidate list in Reykjanesbær in 2026.",
  "reykjanesbaer.M.list.5.occupation": "Care worker",
  "reykjanesbaer.M.list.6.occupation": "Lawyer",
  "reykjanesbaer.M.list.7.occupation": "Captain at Icelandair",
  "reykjanesbaer.M.list.8.occupation": "Aircraft mechanic at Icelandair",
  "reykjanesbaer.M.list.9.occupation": "Store manager at Kaffitár",
  "reykjanesbaer.M.tagline": "Gunnlaugur Kárason leads the Centre Party in Reykjanesbær",
  "reykjanesbaer.S.agenda.0.text": "Equal opportunities and social justice.",
  "reykjanesbaer.S.agenda.0.title": "Equality",
  "reykjanesbaer.S.agenda.1.text": "Quality education and strong school services.",
  "reykjanesbaer.S.agenda.1.title": "Education",
  "reykjanesbaer.S.agenda.2.text": "Strong welfare services for everyone.",
  "reykjanesbaer.S.agenda.2.title": "Welfare",
  "reykjanesbaer.S.list.1.bio": "Guðný Birna Guðmundsdóttir was born on 14 February 1982 and is a qualified nurse with an MPA and an MBA from the University of Iceland. She has served on the Reykjanesbær Town Council since 2014 and is President of the Town Council. She is also Secretary of the Social Democratic Alliance and has served as a substitute MP for the South Constituency on three occasions. Under her leadership, the municipality’s debt has been reduced substantially and property taxes have been lowered for nine consecutive years.",
  "reykjanesbaer.S.list.1.interests.0": "Financial management and debt reduction",
  "reykjanesbaer.S.list.1.interests.1": "School development and education",
  "reykjanesbaer.S.list.1.interests.2": "Housing and the town’s growth",
  "reykjanesbaer.S.list.1.interests.3": "Welfare services",
  "reykjanesbaer.S.list.1.interests.4": "Inclusion of refugees",
  "reykjanesbaer.S.list.1.occupation": "President of the Town Council and Secretary of the Social Democratic Alliance",
  "reykjanesbaer.S.list.10.occupation": "Social worker and flight attendant",
  "reykjanesbaer.S.list.11.occupation": "Project manager and marketing manager",
  "reykjanesbaer.S.list.12.occupation": "Social worker in child protection",
  "reykjanesbaer.S.list.13.occupation": "Deckhand",
