  "reykjavik.A.list.8.occupation": "Operations manager",
  "reykjavik.A.list.9.occupation": "Office worker, project manager",
  "reykjavik.A.tagline": "Housing should be homes — built for people, not investors",
  "reykjavik.B.agenda.0.text": "The list reflects those who want to change the priorities in the governance of Reykjavík; the goal is radical changes to the city’s policy direction.",
  "reykjavik.B.agenda.0.title": "Policy shift",
  "reykjavik.B.agenda.1.text": "Ensure housing security for all residents and increase the supply of affordable housing.",
  "reykjavik.B.agenda.1.title": "Housing security",
  "reykjavik.B.agenda.2.text": "Resolve preschool waiting list issues; prepare education for future generations.",
  "reykjavik.B.agenda.2.title": "Preschools and education",
  "reykjavik.B.agenda.3.text": "Commitment to sustainable development and renewable energy in all city operations.",
  "reykjavik.B.agenda.3.title": "Environmental issues",
  "reykjavik.B.agenda.4.text": "Development of a strong infrastructure system that serves all neighbourhoods equally.",
  "reykjavik.B.agenda.4.title": "Infrastructure",
  "reykjavik.B.agenda.5.text": "Healthcare services and dignity in later life — the foundation of a flourishing society.",
  "reykjavik.B.agenda.5.title": "Healthcare and elderly care services",
  "reykjavik.B.list.1.bio": "Einar Þorsteinsson was born on 24 December 1978 and worked as a reporter, news presenter and programme editor of Kastljós at RÚV before leaving in 2022 to enter politics. He served as Mayor of Reykjavík from January to February 2025 and leads the Framsóknarflokkurinn list in Reykjavík.",
  "reykjavik.B.list.1.interests.0": "Schools and preschools",
  "reykjavik.B.list.1.interests.1": "Transport",
  "reykjavik.B.list.1.interests.2": "Services for the elderly",
  "reykjavik.B.list.1.interests.3": "Efficiency in city operations",
