  "reykjavik.B.list.28.occupation": "Producer",
  "reykjavik.B.list.29.occupation": "Assistant director, youth centre",
  "reykjavik.B.list.3.bio": "Þorvaldur Daníelsson, known as Valdi, founded Hjólakraftur in 2012 — a health initiative that encourages children and young people to be physically active through cycling. He received recognition as Reykjavík Citizen of the Year 2020 for this work. He is an alternate City Councillor for Framsóknarflokkurinn.",
  "reykjavik.B.list.3.interests.0": "Fitness and sports",
  "reykjavik.B.list.3.interests.1": "Services for young people",
  "reykjavik.B.list.3.interests.2": "Cycling and environmentally friendly transport",
