  "reykjavik.B.list.39.occupation": "Film and television producer",
  "reykjavik.B.list.4.bio": "Halldór Bachmann is a communications and marketing specialist with extensive experience in Icelandic and international companies. He has worked for MasterCard and Icelandair and is known as an announcer at KR basketball games. He currently works for Almenni Pension Fund.",
  "reykjavik.B.list.4.interests.0": "Communications and promotion",
  "reykjavik.B.list.4.interests.1": "Finance and pension protection",
