  "reykjavik.B.list.46.occupation": "Former city councillor, former minister",
  "reykjavik.B.list.5.bio": "Andrea Edda Guðlaugsdóttir is an economics student and is in 5th place on the B-list (Framsóknarflokkurinn) in the 2026 Reykjavík City Council elections.",
  "reykjavik.B.list.5.occupation": "Economics student, academic adviser",
  "reykjavik.B.list.6.occupation": "Substance abuse counsellor",
  "reykjavik.B.list.7.occupation": "Bridge builder, MMS Education Centre",
  "reykjavik.B.list.8.occupation": "Actor",
  "reykjavik.B.list.9.occupation": "Visual artist, designer",
  "reykjavik.B.tagline": "Towards a better city — change as a priority",
  "reykjavik.C.agenda.0.text": "Funding should be prioritised for core services, not wasteful projects or duplicated operations; reduce costs and bureaucracy.",
  "reykjavik.C.agenda.0.title": "Citizens first",
  "reykjavik.C.agenda.1.text": "Simplify operations; reduce the number of committees, cross-party committees and departments; lower property taxes; oppose the city competing with the private sector.",
  "reykjavik.C.agenda.1.title": "Efficiency",
  "reykjavik.C.agenda.2.text": "Continue record-level building plans; zone plots for 2,000 homes per year; faster and cheaper construction.",
  "reykjavik.C.agenda.2.title": "Housing construction",
  "reykjavik.C.agenda.3.text": "Develop Skerjafjörður, Ártúnshöfði, Keldur and Vatnsmýri (in place of the airport) as mixed-use neighbourhoods.",
  "reykjavik.C.agenda.3.title": "New neighbourhoods",
  "reykjavik.C.agenda.4.text": "Real choice in all compulsory schools; free schooling regardless of operating model; free preschools for 5-year-olds.",
  "reykjavik.C.agenda.4.title": "Education",
  "reykjavik.C.agenda.5.text": "Sell assets on the basis of professional valuation; increase the private sector’s share through competitive tendering.",
  "reykjavik.C.agenda.5.title": "Asset management",
  "reykjavik.C.list.1.bio": "Björg Magnúsdóttir was born on 9 April 1985 and is a media professional, screenwriter and politician. She worked as a news reporter and presenter at RÚV and has written two novels. She won Viðreisn’s leadership election in Reykjavík in January 2026.",
  "reykjavik.C.list.1.interests.0": "Media and culture",
  "reykjavik.C.list.1.interests.1": "School affairs and preschools",
  "reykjavik.C.list.1.interests.2": "Housing",
  "reykjavik.C.list.1.interests.3": "Streamlining administration",
